exploreUrl:
@js:
sort=[];
push=(title,url,type1,type2)=>sort.push({
		title: title,
		url: url,
		style: {
				layout_flexGrow: type1,
				layout_flexBasisPercent: type2
			}
	});

		fl=[
	["男生",
["武侠","仙侠","玄幻","奇幻","科幻","灵异","职场","都市","历史","军事","游戏","竞技","同人","轻小说","其他"]],
	["女生",
["古代言情","现代言情","青春校园","玄幻奇幻","武侠仙侠","悬疑灵异","游戏竞技","科幻","同人","女尊","其他"]]];

fl.map([title,list]=>{

	push(title, null, 1, 1);
	  list.map((title,type)=>{
	  	url = `@js:
link_Urlpath = "/sort/list";
link_Params = {
	 "gender": "0",
	  "limit": "20",
	  "major": "${java.encodeURI(title)}",
	  "minor": "",
  	"start": (page-1)*20,
  	"type": "sort_pop"
	};
url = get_sign(link_Urlpath, link_Params);`;

	if(list.length > 3){
		if(type+1 <= list.length - list.length%3)
			 {	push(title, url, 1, 0.25);}
				else{ push(title, url, 0, 0.29);}
				}
				else{ push(title, url, 1, 0.25);}
    	});
	});

JSON.stringify(sort);

jsLib:
function transformString(inputString) {
    let charMap = {"1": "C","2": "H","3": "I","4": "K","5": "M","A": "B","B": "2","C": "D","D": "E","E": "F","F": "G","G": "J","I": "L","J": "N"};
    let result = '';
    for (let i = 0; i < inputString.length; i++) {
        let char = inputString[i];
        if (charMap[char] !== undefined) {
            result += charMap[char];
        } else {
            result += char;
        }
    }
    return result;
}

function get_sign(link_Urlpath, link_Params) {
    const {java} = this;
    var time = String(Date.now());
    let xst = time.substr(0, 10);
    let skey = "797f446d-21ee-442d-bf18-79f3b22e7f06"
    let api_Params = {
        "app_name": "com.wbydq.txtreader",
        "app_vc": "208",
        "app_vn": "2.0.8",
        "dev_id": "995a1caa-4748-3da9-8a79-7de88ffc2700",
        "language": "zh_cn",
        "ts": time,
    }


   obj = Object.assign(api_Params, link_Params);
    p = Object.keys(obj).sort().map(key=>key+"="+obj[key]).join('&');

    url = "https://new.wowonongjia.com";
    if(/new/g.test(link_Urlpath)){
    	url = "https://read.wowonongjia.com";
    	p = String(p).replace("language=zh_cn&","");  	
    	}else{
    		url = url;
      	p = p;
    	}

    	data = url + link_Urlpath + p + xst + "+"  + skey;
    md5text = java.md5Encode(data).toUpperCase();
    let sign = transformString(String(md5text));

    head = JSON.stringify({
	"headers":{
        "xss": sign,
        "xst": xst,
        "User-Agent": "okhttp/4.11.0"
    }});

    return url+link_Urlpath+"?"+p+","+head;
}

