ruleContent.imageDecode:
(function() {
    if (src.indexOf("sr:1") == -1) {
        return result; 
    }
    try {
        var Magua = new JavaImporter();
        Magua.importPackage(Packages.java.io, Packages.android.graphics);
        with(Magua) {
            // 1. 检查正则匹配是否成功
            var match = src.match(/sr:.*?\/(.*?)\..*/);
            if (!match) {
                return result;
            }

            // 2. 检查 MD5 计算逻辑
            var b64Data = match[1];
            var decodedPath = java.base64Decode(b64Data);
            var md5Str = java.md5Encode(decodedPath);
            var lastTwo = md5Str.substring(md5Str.length() - 2);

            var num = (parseInt(lastTwo, 16) % 10) + 5;

            // 3. 开始绘图 (测试是否能正常解码图片)
            var img = BitmapFactory.decodeByteArray(result, 0, result.length);
            if (!img) return result;

            var h = img.getHeight();
            var w = img.getWidth();
            var y = Math.floor(h / num);
            var rem = h % num;

            var newImg = Bitmap.createBitmap(w, h, Bitmap.Config.RGB_565);
            var canvas = new Canvas(newImg);
            var paint = new Paint();

            for (var i = 1; i <= num; i++) {
                var currentSliceH = (i === num) ? (y + rem) : y;
                var srcY = y * (i - 1);

                // 倒序逻辑：第一块画到最下面，最后一块画到最上面
                var dstY = h - srcY - currentSliceH;

                var srcRect = new Rect(0, srcY, w, srcY + currentSliceH);
                var dstRect = new Rect(0, dstY, w, dstY + currentSliceH);
                canvas.drawBitmap(img, srcRect, dstRect, paint);
            }

            var baos = new ByteArrayOutputStream();
            newImg.compress(Bitmap.CompressFormat.JPEG, 90, baos);
            var finalRes = baos.toByteArray();

            img.recycle();
            newImg.recycle();
            return finalRes;
        }
    } catch (e) {
        return result;
    }
})();

