ruleContent.content:
@js:
var res = "";
try {
    var match = result.match(/window\.comicInfo\s*=\s*(.*?)(?:,window\.hideguide|;|<\/script>)/);
    if (match) {
        var json = eval('(' + match[1] + ')');
        var images = json.current_chapter.chapter_img_list;
        var html = [];
        for(var i=0; i<images.length; i++){
            var imgUrl = String(images[i]).replace(/^\/\//, 'https://');
            html.push('<img src="' + imgUrl + '">');
        }
        res = html.join('\n');
    } else {
        res = "解析失败：未匹配到图片数据";
    }
} catch(e) {
    res = "解析报错：" + e.message;
}
res;

