@js:
var url = java.getString('$..txt_addr')
var text = java.cacheFile(url)
var img = java.getString('$..content')
var ims = img.match(/https?:\/\/.+\.(jpg|jpeg|webp)/gi); 
if (ims) {
    imgs = ims.map(x => `<img src="${x}">`).join('\n');
    }
text + imgs

